class Solution {
public:
    vector<int> beautifulIndices(string s, string a, string b, int k) {
        int n = s.size(), na = a.size(), nb = b.size();
        vector<int> ia, ib, ans;

        auto collect = [&](const string& pat, vector<int>& idx) {
            int np = pat.size();
            if (np == 0) return;
            for (int i = 0; i + np <= n; ++i) {
                bool ok = true;
                for (int j = 0; j < np; ++j) {
                    if (s[i + j] != pat[j]) { ok = false; break; }
                }
                if (ok) idx.push_back(i);
            }
        };

        collect(a, ia);
        collect(b, ib);

        int m = ib.size();
        if (m == 0) return ans;

        for (int i : ia) {
            int l = lower_bound(ib.begin(), ib.end(), i - k) - ib.begin();
            int r = upper_bound(ib.begin(), ib.end(), i + k) - ib.begin();
            if (l < r) ans.push_back(i);
        }

        return ans;
    }
};
```
